// Aggregate last 7 days of metrics from Google Sheets
// Expected sheet columns: date, revenue, new_customers, churn, support_tickets, website_sessions, conversions

const rows = $input.all().map(item => item.json);

if (!rows || rows.length === 0) {
  return { json: { error: 'No metrics data found in sheet', rows: 0 } };
}

// Get last 7 rows (most recent week)
const weekRows = rows.slice(-7);

const sum = (key) => weekRows.reduce((acc, r) => acc + (parseFloat(r[key]) || 0), 0);
const avg = (key) => weekRows.length > 0 ? (sum(key) / weekRows.length).toFixed(1) : 0;

// Calculate week-over-week change (compare last 7 vs previous 7)
const prevWeek = rows.slice(-14, -7);
const wow = (key) => {
  const curr = sum(key);
  const prev = prevWeek.reduce((acc, r) => acc + (parseFloat(r[key]) || 0), 0);
  if (prev === 0) return 'N/A';
  const change = (((curr - prev) / prev) * 100).toFixed(1);
  return (change >= 0 ? '+' : '') + change + '%';
};

const metrics = {
  week_of: new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }),
  total_revenue: '$' + sum('revenue').toFixed(2),
  revenue_wow: wow('revenue'),
  new_customers: sum('new_customers'),
  new_customers_wow: wow('new_customers'),
  churn_count: sum('churn'),
  support_tickets: sum('support_tickets'),
  support_tickets_wow: wow('support_tickets'),
  website_sessions: sum('website_sessions'),
  website_sessions_wow: wow('website_sessions'),
  conversions: sum('conversions'),
  conversion_rate: weekRows.length > 0 
    ? ((sum('conversions') / sum('website_sessions')) * 100).toFixed(2) + '%' 
    : '0%',
  data_rows: weekRows.length,
  date_range: (weekRows[0]?.date || '') + ' — ' + (weekRows[weekRows.length-1]?.date || '')
};

return { json: metrics };

